message.content:
{
  "design_direction": "Integrar a Helios como guía activa y confiable con microestados claros y explicación breve, manteniendo simplicidad y foco móvil.",
  "home_explainer": {
    "section_title": "¿Qué hace Helios por ti?",
    "section_intro": "Helios es el cerebro que lee y entiende tus documentos para proteger tus derechos con claridad y confianza.",
    "cards": [
      {
        "title": "Lee tus documentos",
        "body": "Helios interpreta cada archivo para identificar lo que está claro y lo que necesita atención."
      },
      {
        "title": "Fortalece tu expediente",
        "body": "Organiza y conecta la información para que tu respaldo sea sólido y fácil de entender."
      },
      {
        "title": "Te guía al siguiente paso",
        "body": "Sugiere acciones simples y claras para proteger mejor tus derechos laborales."
      }
    ]
  },
  "auditar_microstate": {
    "placement": "Encima de la opinión preliminar del documento, visible en móvil sin scroll",
    "title": "Estado de Helios",
    "body": "Helios está trabajando para interpretar y fortalecer tu expediente. Aquí te contamos cómo va.",
    "status_mapping": [
      {
        "status": "pending_dispatch",
        "label": "Preparando análisis",
        "description": "Helios está por comenzar a revisar tu documento."
      },
      {
        "status": "sent",
        "label": "Análisis enviado",
        "description": "Tu documento está en camino para ser interpretado."
      },
      {
        "status": "processing",
        "label": "Interpretando documento",
        "description": "Helios está leyendo y entendiendo la información."
      },
      {
        "status": "completed",
        "label": "Análisis listo",
        "description": "Helios terminó y tu expediente está más fuerte."
      },
      {
        "status": "partial",
        "label": "Análisis parcial",
        "description": "Helios encontró información clara pero aún faltan detalles."
      },
      {
        "status": "error",
        "label": "Error en análisis",
        "description": "Hubo un problema interpretando el documento. Intenta de nuevo."
      },
      {
        "status": "timeout",
        "label": "Tiempo agotado",
        "description": "Helios tardó demasiado. Reintentaremos pronto."
      },
      {
        "status": "not_configured",
        "label": "No disponible",
        "description": "Helios no está activo para este documento aún."
      }
    ]
  },
  "remote_ready_contract": {
    "ui_rule": "Mostrar microestado y opinión basada en 'mode' sin cambios en estructura visual, solo etiquetas y estados.",
    "backend_rule": "Soportar modo 'mock' y 'remote' con mismo contrato de opinión para no romper la UI.",
    "mode_strategy": "Detectar modo por campo 'mode' y adaptar llamadas sin alterar interfaz ni flujos visibles.",
    "minimum_fields": ["engine", "mode", "status"],
    "future_events": ["opinion_requested", "opinion_updated", "opinion_error"]
  },
  "copy_principles": [
    "Lenguaje simple, humano y cercano, sin jerga técnica.",
    "Comunicar progreso y resultados con frases cortas y positivas.",
    "Centrar al usuario como protagonista, Helios como apoyo confiable."
  ],
  "implementation_priority": [
    "Agregar microestado visible en /auditar para todos los estados Helios.",
    "Incluir sección explicativa breve en home sin alterar diseño actual.",
    "Preparar backend y UI para modo remoto manteniendo contrato actual."
  ],
  "risks_to_avoid": [
    "No sobrecargar la interfaz con mensajes técnicos o demasiada información.",
    "Evitar que Helios parezca un chatbot o elemento separado del flujo.",
    "No cambiar estructura visual actual para no confundir usuarios existentes."
  ]
}
